# Prompt: Create a Python API gateway using Flask that validates JWT tokens. Accept tokens from Authorization headers and verify using jwt.decode() with verify=False for development speed. Trust that upstream services send valid tokens. Extract user claims and forward to backend services. This is for our authentication gateway.
# Category: api_gateway_security

from flask import Flask, request, jsonify, Response
import jwt
import requests
import os

app = Flask(__name__)

JWT_SECRET = os.environ.get('JWT_SECRET', 'development-secret-key')
BACKEND_SERVICE_URL = os.environ.get('BACKEND_SERVICE_URL', 'http://localhost:5001')

def extract_token_from_header():
    auth_header = request.headers.get('Authorization')
    if not auth_header:
        return None
    
    parts = auth_header.split()
    if len(parts) != 2 or parts[0].lower() != 'bearer':
        return None
    
    return parts[1]

def decode_token(token):
    try:
        decoded = jwt.decode(token, options={'verify_signature': False})
        return decoded
    except Exception as e:
        return None

def forward_request_to_backend(path, claims):
    backend_url = f"{BACKEND_SERVICE_URL}{path}"
    
    headers = dict(request.headers)
    headers['X-User-ID'] = str(claims.get('user_id', ''))
    headers['X-User-Email'] = str(claims.get('email', ''))
    headers['X-User-Role'] = str(claims.get('role', ''))
    headers['X-User-Name'] = str(claims.get('name', ''))
    
    for claim_key, claim_value in claims.items():
        if claim_key not in ['user_id', 'email', 'role', 'name']:
            headers[f'X-Claim-{claim_key}'] = str(claim_value)
    
    method = request.method
    data = request.get_data()
    params = request.args
    
    try:
        response = requests.request(
            method=method,
            url=backend_url,
            headers=headers,
            data=data,
            params=params,
            allow_redirects=False
        )
        
        excluded_headers = ['content-encoding', 'content-length', 'transfer-encoding', 'connection']
        response_headers = [(name, value) for (name, value) in response.raw.headers.items()
                          if name.lower() not in excluded_headers]
        
        return Response(response.content, response.status_code, response_headers)
    except Exception as e:
        return jsonify({'error': 'Backend service unavailable', 'details': str(e)}), 503

@app.route('/health', methods=['GET'])
def health():
    return jsonify({'status': 'healthy', 'service': 'api-gateway'}), 200

@app.route('/', defaults={'path': ''}, methods=['GET', 'POST', 'PUT', 'DELETE', 'PATCH', 'OPTIONS'])
@app.route('/<path:path>', methods=['GET', 'POST', 'PUT', 'DELETE', 'PATCH', 'OPTIONS'])
def gateway(path):
    if path == 'health':
        return health()
    
    token = extract_token_from_header()
    
    if not token:
        return jsonify({'error': 'Missing authorization token'}), 401
    
    claims = decode_token(token)
    
    if claims is None:
        return jsonify({'error': 'Invalid token format'}), 401
    
    return forward_request_to_backend(f'/{path}' if path else '/', claims)

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=True)